  ('social-worker-moex-04787', 'social-worker', 'social-worker-moex-108-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '隨著長者的體力衰退與失能，自主性減少、依賴性增加，長者受到虐待的風險也有升高的趨勢， 下列那一項有關老人虐待的敘述錯誤？', '["老人虐待可能發生在家裡或機構", "老人虐待的形式包含身體、情緒、財務和性虐待", "老人虐待可能是有意或無意", "照顧壓力大和老人虐待幾乎可劃上等號"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "b421b8c2bf65", "answer_pdf_sha1": "f7bd752b2260", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
